    /// <summary>
    /// set the level of leverage for a market
    /// </summary>
    /// <remarks>
    /// See <see href="https://www.weex.com/api-doc/contract/Account_API/UpdateLeverageTRADE"/>  <br/>
    /// <list type="table">
    /// <item>
    /// <term>params</term>
    /// <description>
    /// object : extra parameters specific to the exchange API endpoint
    /// </description>
    /// </item>
    /// <item>
    /// <term>params.marginMode</term>
    /// <description>
    /// string : 'cross' or 'isolated' (default is 'cross' if specific leverage parameters are not provided)
    /// </description>
    /// </item>
    /// <item>
    /// <term>params.crossLeverage</term>
    /// <description>
    /// number : *cross margin mode only* leverage for cross margin mode when marginMode is 'cross'
    /// </description>
    /// </item>
    /// <item>
    /// <term>params.isolatedLongLeverage</term>
    /// <description>
    /// number : *isolated margin mode only* leverage for long positions when marginMode is 'isolated'
    /// </description>
    /// </item>
    /// <item>
    /// <term>params.isolatedShortLeverage</term>
    /// <description>
    /// number : *isolated margin mode only* leverage for short positions when marginMode is 'isolated'
    /// </description>
    /// </item>
    /// </list>
    /// </remarks>
    /// <returns> <term>object</term> response from the exchange.</returns>
    public async Task<Dictionary<string, object>> SetLeverage(Int64 leverage, string symbol = null, Dictionary<string, object> parameters = null)
    {
        var res = await this.setLeverage(leverage, symbol, parameters);
        return ((Dictionary<string, object>)res);
    }
